const { session_id, tool_calls, tokens_used, errors, duration_ms } = $json;
return {
  session_id: session_id || 'unknown',
  tool_calls: tool_calls || 0,
  tokens_used: tokens_used || 0,
  errors: errors || 0,
  duration_ms: duration_ms || 0,
  recorded_at: new Date().toISOString()
};

const metrics = $json;
const costPerToken = 0.000003;
const estimatedCost = metrics.tokens_used * costPerToken;
const tokenPerSecond = metrics.duration_ms > 0 ? (metrics.tokens_used / (metrics.duration_ms / 1000)).toFixed(1) : 0;
const errorRate = metrics.tool_calls > 0 ? ((metrics.errors / metrics.tool_calls) * 100).toFixed(1) : 0;
const bottlenecks = [];
if (metrics.tool_calls > 50) bottlenecks.push('High tool call count - consider batching');
if (metrics.tokens_used > 50000) bottlenecks.push('High token usage - consider context optimization');
if (metrics.errors > 5) bottlenecks.push('Elevated error rate - check rate limits');
if (Number(tokenPerSecond) < 10) bottlenecks.push('Low throughput - consider parallel execution');
return {
  ...metrics,
  estimated_cost: estimatedCost.toFixed(4),
  token_throughput: tokenPerSecond,
  error_rate: `${errorRate}%`,
  bottlenecks,
  health: bottlenecks.length === 0 ? 'good' : bottlenecks.length <= 2 ? 'fair' : 'poor'
};

const ltmPath = '/home/timothy/Project/Arch-Mk2/ltm/store';
const fs = require('fs');
const path = require('path');
if (!fs.existsSync(ltmPath)) fs.mkdirSync(ltmPath, { recursive: true });
const perfFile = path.join(ltmPath, 'performance.jsonl');
const record = {
  id: `perf_${Date.now()}`,
  ts: new Date().toISOString(),
  session_id: $json.session_id,
  tool_calls: $json.tool_calls,
  tokens_used: $json.tokens_used,
  estimated_cost: $json.estimated_cost,
  bottlenecks: $json.bottlenecks,
  health: $json.health
};
fs.appendFileSync(perfFile, JSON.stringify(record) + '\n');
return record;

return {
  alert: true,
  severity: 'warning',
  message: `Performance degradation detected: ${$json.bottlenecks.join('; ')}`,
  recommended_action: '/compact to reduce context, or switch to batching pattern'
};
